    [
        context_item("Warm-up — Activity Synthesis", "• Consider asking:\n\n◦ “Is anyone’s estimate less than _____? Is anyone’s\nestimate greater than _____?”\n◦ “Based on this discussion, does anyone want to\nrevise their estimate?”\n• “What would help us be more sure of our estimate?”\n(More tick marks that are equally spaced. Marks of\nmultiples of 10.)", line(107)),
