        context_item("Activity 1 — Student Task Statement", "1. Lin says the time shown on\nthe clock is 1:37 p.m.\nDiego says the time is 1:35\np.m.\nWho do you agree with?\nExplain or show your\nreasoning.\n2. What time is shown on each clock?\n\nA                          B\n\nC                          D", line(147)),
